import{_ as i,o as t,c as l,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3135_凌航/20260430/G11_前十大客戶與供應商穩定度_投資研究員.md","filePath":"審計報告庫/經營審計/3135_凌航/20260430/G11_前十大客戶與供應商穩定度_投資研究員.md"}'),r={name:"審計報告庫/經營審計/3135_凌航/20260430/G11_前十大客戶與供應商穩定度_投資研究員.md"};function o(n,a,s,h,d,_){return t(),l("div",null,[...a[0]||(a[0]=[e('<h1 id="g11-前十大客戶與供應商穩定度-投資研究員-審計報告" tabindex="-1">G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告 <a class="header-anchor" href="#g11-前十大客戶與供應商穩定度-投資研究員-審計報告" aria-label="Permalink to &quot;G11: 前十大客戶與供應商穩定度 - 投資研究員 審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>近三年中，前十大客戶與供應商變動情形為何？客戶集中度風險是否正在惡化？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：雙軌合計93%，集中度高。2025毛利率反彈至19.12%，供應鏈依賴韓系原廠未變。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：2026年3月最新數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：2025營收25.61億（+40%），毛利率19.12%，EPS 4.83。2024毛利率僅2.44%。Q1累計營收39.58億（+178%）。雙軌佔比93%，LTA保障供貨，庫存3-4個月。</li><li><strong>診斷見解</strong>：毛利率反彈係週期反轉，非結構優化。集中度未改善，風險持續。工控轉型（7%→10-20%）放量時程未定，電競依賴短期難解。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="客戶端-集中度與變動" tabindex="-1">客戶端：集中度與變動 <a class="header-anchor" href="#客戶端-集中度與變動" aria-label="Permalink to &quot;客戶端：集中度與變動&quot;">​</a></h3><ul><li><strong>核心</strong>：營收三大來源：系統整合（47%）、電競（46%）、工控（7%），前兩大合計93%。公司未公開前十大客戶名單。</li><li><strong>見解</strong>：工控黏著度高，目標2026年提升至10-20%。Q1營收+178%部分來自AI邊緣伺服器訂單。</li></ul><h3 id="供應商端-供貨穩定性" tabindex="-1">供應商端：供貨穩定性 <a class="header-anchor" href="#供應商端-供貨穩定性" aria-label="Permalink to &quot;供應商端：供貨穩定性&quot;">​</a></h3><ul><li><strong>核心</strong>：上游為韓系三廠寡佔，已簽LTA，庫存3-4個月。CSP包下大量產能，新產能2027年後開出。</li><li><strong>見解</strong>：LTA保障短期供貨，但凌航議價力弱，庫存緩衝不足以支撐長期斷鏈風險。</li></ul><h3 id="掉單壓力測試" tabindex="-1">掉單壓力測試 <a class="header-anchor" href="#掉單壓力測試" aria-label="Permalink to &quot;掉單壓力測試&quot;">​</a></h3><ul><li><strong>核心</strong>：Top 1客戶假設佔比15-20%，若歸零衝擊3.84-5.12億營收，EPS減4.45-5.61元。</li><li><strong>見解</strong>：揭露對單一客戶的脆弱性，2024毛利率2.44%已證明缺乏利潤緩衝。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析（Skepticism Mandate） <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析（Skepticism Mandate）&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：客戶集中度惡化風險——系統整合與電競雙軌合計 93%，且未見明顯分散化趨勢。若電競市場因消費衰退（如全球 PC/NB 出貨量下滑）而萎縮，佔比 46% 的電競客戶群將同步縮減，公司缺乏其他成長引擎來填補缺口。工控（7%→10-20%）的轉型尚處早期，放量時程與規模仍具高度不確定性。</li><li><strong>空頭風險二</strong>：供應鏈過度依賴韓系原廠——凌航 70% 營收來自 DRAM，而全球 DRAM 供應由三星、SK 海力士、美光三廠寡占。當 CSP（如 AWS、微軟）包下大量產能時，中游模組廠的貨源分配將被邊緣化。LTA 雖提供保障，但協議條件（價格、數量）在供不應求時未必對凌航有利，原廠漲價壓力將直接侵蝕毛利率——2024 年毛利率 2.44% 的前車之鑑，揭示此風險的實質衝擊量級。此外，地緣政治風險（美中科技戰、台海局勢）可能進一步扭曲供應鏈配置，凌航作為台灣廠商，在戰略物資分配中的位階並不明確。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源（Veracity Check） <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源（Veracity Check）&quot;">​</a></h2><ul><li><strong>FinMind</strong>：OK。2024 H1/FY、2025 Q1-Q4/FY 損益表、月營收、估值數據完整取得。</li><li><strong>yfinance</strong>：未執行（FinMind 數據已涵蓋）。</li><li><strong>年報/法說</strong>：凌航 2025 年 8 月上市，年報電子書已公開（2024 Q4 合併報表可查）；2023 Q4 合併 PDF 位於年報資料庫。法說會資訊來自鉅亨網（2025-12-15 報導）與公開資訊觀測站。</li><li><strong>關鍵核對碼</strong>： <ul><li>2025 FY 營收 2,561,142 千元 → FinMind Revenue 確認</li><li>2025 FY 毛利 489,625 千元 / 營收 2,561,142 千元 = 19.12%</li><li>2025 FY EPS 4.83 元 → FinMind 確認</li><li>客戶結構：系統整合 47%、電競 46%、工控 7% → 鉅亨網 2025-12-15 報導</li><li>LTA 與庫存 3-4 個月 → 鉅亨網、優分析報導</li><li>2026 Q1 累計營收 39.58 億元（YoY +177.96%）→ FinMind 月營收合計</li></ul></li></ul>',20)])])}const g=i(r,[["render",o]]);export{u as __pageData,g as default};
